param([Parameter(Mandatory=$true)][string]$CoarseRunId,[Parameter(Mandatory=$true)][string]$FineRunId,[string]$RunId='')
Set-StrictMode -Version Latest;$ErrorActionPreference='Stop';$projectRoot=(Resolve-Path (Join-Path $PSScriptRoot '..\..')).Path;$repoRoot=(Resolve-Path (Join-Path $projectRoot '..\..')).Path;$workspaceRoot=Split-Path -Parent $repoRoot;$runsRoot=Join-Path $workspaceRoot 'artifacts\projects\rf_quadrupole_collision_cooling\runs';$python=Join-Path $repoRoot '.venv\Scripts\python.exe'
foreach($id in @($CoarseRunId,$FineRunId)){& $python (Join-Path $repoRoot 'common\contracts\artifact_naming.py') run $id;if($LASTEXITCODE-ne 0){throw "Invalid source run: $id"}};$coarseDir=Join-Path $runsRoot $CoarseRunId;$fineDir=Join-Path $runsRoot $FineRunId;$coarse=Join-Path $coarseDir 'results\rf_hybrid_mesh_field_samples.csv';$fine=Join-Path $fineDir 'results\rf_hybrid_mesh_field_samples.csv';$sourceManifests=@((Join-Path $coarseDir 'run_manifest.json'),(Join-Path $fineDir 'run_manifest.json'));foreach($path in @($coarse,$fine)+$sourceManifests){if(-not(Test-Path -LiteralPath $path -PathType Leaf)){throw "Source evidence missing: $path"}}
if([string]::IsNullOrWhiteSpace($RunId)){$RunId=(Get-Date -Format 'yyyyMMdd_HHmmss')+'__analysis__python__rf-hybrid-mesh-comparison'};& $python (Join-Path $repoRoot 'common\contracts\artifact_naming.py') run $RunId;if($LASTEXITCODE-ne 0){throw "Invalid run id: $RunId"};$runDir=Join-Path $runsRoot $RunId;if(Test-Path -LiteralPath $runDir){throw "Run exists: $runDir"};$inputDir=Join-Path $runDir 'inputs';$resultDir=Join-Path $runDir 'results';New-Item -ItemType Directory -Force -Path $inputDir,$resultDir|Out-Null
$analysis=Join-Path $inputDir 'compare_rf_hybrid_mesh.py';$contract=Join-Path $inputDir 'rf_hybrid_mesh_candidate.json';$runner=Join-Path $inputDir 'run_rf_hybrid_mesh_comparison.ps1.txt';Copy-Item (Join-Path $projectRoot 'analysis\compare_rf_hybrid_mesh.py') $analysis;Copy-Item (Join-Path $projectRoot 'config\rf_hybrid_mesh_candidate.json') $contract;Copy-Item $PSCommandPath $runner;$metrics=Join-Path $resultDir 'rf_hybrid_mesh_comparison.json';$summary=Join-Path $runDir 'summary.json';$runConfig=Join-Path $runDir 'run_config.json';$writer=Join-Path $repoRoot 'common\contracts\write_run_manifest.py'
[ordered]@{schema_version=1;run_id=$RunId;project='rf_quadrupole_collision_cooling';mode='rf_full_device_hybrid_mesh_comparison';project_root=$repoRoot;inputs=[ordered]@{analysis=$analysis;contract=$contract;runner=$runner;source_manifests=$sourceManifests;coarse_samples=$coarse;fine_samples=$fine};parameters=[ordered]@{coarse_run_id=$CoarseRunId;fine_run_id=$FineRunId;particle_tracking=$false};formal_gate_passed=$false}|ConvertTo-Json -Depth 7|Set-Content $runConfig -Encoding UTF8;[ordered]@{schema_version=1;role='rf_hybrid_mesh_comparison_summary';status='interrupted'}|ConvertTo-Json|Set-Content $summary -Encoding UTF8;& $python $writer --run-config $runConfig --status interrupted --software 'Python 3.11'
try{& $python $analysis --coarse $coarse --fine $fine --contract $contract --output $metrics;if($LASTEXITCODE-ne 0){throw 'RF hybrid comparison execution failed.'}}catch{[ordered]@{schema_version=1;role='rf_hybrid_mesh_comparison_summary';status='failed';reason=$_.Exception.Message}|ConvertTo-Json|Set-Content $summary -Encoding UTF8;& $python $writer --run-config $runConfig --status failed --software 'Python 3.11';throw};$report=Get-Content -LiteralPath $metrics -Raw -Encoding UTF8|ConvertFrom-Json;[ordered]@{schema_version=1;role='rf_hybrid_mesh_comparison_summary';status='success';decision=$report.status;paired_particle_diagnostic_allowed=$report.paired_particle_diagnostic_allowed;particle_acceptance_allowed=$report.particle_acceptance_allowed}|ConvertTo-Json|Set-Content $summary -Encoding UTF8;& $python $writer --run-config $runConfig --status success --software 'Python 3.11' --output $metrics --output $summary;if($LASTEXITCODE-ne 0){throw 'Final manifest failed.'};Write-Output "STATUS=PASS RUN_ID=$RunId FIELD_DECISION=$($report.status) PAIRED_PARTICLE_DIAGNOSTIC_ALLOWED=true"
